import{_ as e,o as t,c as s,a5 as c}from"./chunks/framework.B5tqjWbr.js";const C=JSON.parse('{"title":"概念：PCS 储能 DC-DC 与模式状态机","description":"","frontmatter":{"date":"2026-06-22T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：PCS 储能 DC-DC 与模式状态机","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0046-pcs-storage-dcdc-mode-state-machine.html` 的源稿。"},"headers":[],"relativePath":"content/power/concepts/pcs/storage-dcdc-mode-state-machine.md","filePath":"content/power/concepts/pcs/storage-dcdc-mode-state-machine.md","lastUpdated":null}'),o={name:"content/power/concepts/pcs/storage-dcdc-mode-state-machine.md"};function n(r,a,i,d,l,p){return t(),s("div",null,[...a[0]||(a[0]=[c(`<h1 id="概念-pcs-储能-dc-dc-与模式状态机" tabindex="-1">概念：PCS 储能 DC-DC 与模式状态机 <a class="header-anchor" href="#概念-pcs-储能-dc-dc-与模式状态机" aria-label="Permalink to &quot;概念：PCS 储能 DC-DC 与模式状态机&quot;">​</a></h1><p>本页是 <code>lessons/0046-pcs-storage-dcdc-mode-state-machine.html</code> 的源稿。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>双向 DC-DC 变换器（bidirectional DC-DC converter）连接电池和直流母线。PCS 模式状态机（PCS mode state machine）协调待机、预充、并网充电、并网放电、离网构网和故障停机。</p><h2 id="为什么-ups-pcs-需要它" tabindex="-1">为什么 UPS/PCS 需要它 <a class="header-anchor" href="#为什么-ups-pcs-需要它" aria-label="Permalink to &quot;为什么 UPS/PCS 需要它&quot;">​</a></h2><p>UPS 软件骨架里的状态机、保护、故障锁存、通信和参数管理都可扩展到 PCS，但 PCS 还要处理电池、BMS 和并网/离网功率流。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>charge:    grid -&gt; AC/DC -&gt; DC bus -&gt; DC/DC -&gt; battery</span></span>
<span class="line"><span>discharge: battery -&gt; DC/DC -&gt; DC bus -&gt; DC/AC -&gt; grid/load</span></span>
<span class="line"><span>allowed = precharge_ok and contactor_ok and no_fault and command_valid</span></span></code></pre></div><h2 id="一个仿真任务" tabindex="-1">一个仿真任务 <a class="header-anchor" href="#一个仿真任务" aria-label="Permalink to &quot;一个仿真任务&quot;">​</a></h2><p>设计 Standby -&gt; Precharge -&gt; GridCharge -&gt; GridDischarge -&gt; GridForming -&gt; Fault 状态机，注入 BMS 禁止和 PLL 失锁事件。</p><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能画出 PCS 能量路径。</li><li>能列出并网充电、并网放电、离网构网的进入条件。</li><li>能说明故障闭环如何关闭 PWM、断开接触器并上报状态。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><p>BMS 限制、PCS 故障和调度命令的优先级如何阅读？</p>`,14)])])}const g=e(o,[["render",n]]);export{C as __pageData,g as default};
